    //加载子包
    LoadSubpackage(callback) {
        if (SdkUtil.subpkgnum == 0) {

            if (new Date().getTime() - SdkUtil.qidongTime >= 3000) {
                if (callback != null) {
                    callback();
                }
            } else {
                let jinge = 3000 - (new Date().getTime() - SdkUtil.qidongTime);
                Laya.timer.once(jinge, this, function () {
                    if (callback != null) {
                        callback();
                    }
                })
            }
            return;
        }
        console.log("加载子包开始" + SdkUtil.subpkgnum);
        SdkUtil.LoadSubpackage2("package" + SdkUtil.subpkgnum, function () {
            SdkUtil.subpkgnum -= 1;
            SdkUtil.LoadSubpackage(callback);
        })
    },
