    ShowVideo1() {
        var kaipin1 = SdkUtil.GetConfig("skp");
        if (kaipin1 == 0 || kaipin1 == null) {
            return false;
        }

        var ss = kaipin1.split("_");
        if (ss[0] == null || ss[1] == null || ss[2] == null) {
            return false;
        }
        if (SdkUtil.RandomInt(0, 100) >= parseInt(ss[0])) {
            return false;
        }
        if (SdkUtil.preClickTime1 == null) {
            SdkUtil.preClickTime1 = SdkUtil.qidongTime + parseInt(ss[1]);
        }

        if (new Date().getTime() < SdkUtil.preClickTime1) {
            return false;
        }
        SdkUtil.preClickTime1 = new Date().getTime() + parseInt(ss[2]);
        SdkUtil.TDEvent("视频点击2");
        window["SdkUtil"].ShowVideo(function (code) {
            if (code == 1) {
                SdkUtil.TDEvent("视频完成2");
            }
        });

        return true;
    },
